class Solution {
    public int maximumLength(String s) {
        int n = s.length();
        int maxLen = -1;
        for (char c = 'a'; c <= 'z'; c++) {
            int count = 0, len = 0, prev = 0;
            for (int i = 0; i < n; i++) {
                if (s.charAt(i) == c) {
                    len++;
                    if (i == n - 1 || s.charAt(i + 1) != c) {
                        if (len >= 3) count++;
                        if (len >= 2) prev++;
                        if (len >= 1) maxLen = Math.max(maxLen, len);
                    }
                } else {
                    if (len >= 3) count++;
                    if (len >= 2) prev++;
                    len = 0;
                }
            }
            if (count >= 1) maxLen = Math.max(maxLen, Math.min(prev >= 3 ? maxLen : (prev >= 2 ? maxLen - 1 : maxLen - 2), len));
        }
        return maxLen;
    }
}
